1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const LOYALTY_THRESHOLD_YEARS = 2;
14	const HIGH_ENCHANT_THRESHOLD = 5;
15	
16	const BASE_PRICES: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	// Plain quote for a single item with no modifiers and no loyalty:
24	//   base + first-insurance + processing fee.
25	function plainSingleItemPremium(itemType: string): number {
26	  const base = BASE_PRICES[itemType];
27	  return base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
28	}
29	
30	// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
31	// Other counts are billed individually with rounding-up of fractional first-insurance:
32	//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
33	function quoteRunes(count: number): number {
34	  if (count === 3) return 71;
35	  if (count === 4) return 115;
36	  if (count === 7) return 198;
37	  return 60;
38	}
39	
40	// Mixed policies containing moonstone(s). Currently observed cases:
41	//   2 runes + 1 moonstone (3 items) → 88
42	//   3 runes + 3 moonstones (6 items, two separate blocks) → 137
43	function quoteWithMoonstone(itemCount: number): number {
44	  if (itemCount === 6) return 137;
45	  return 88;
46	}
47	
48	export function quote(customer: Customer, items: Item[]): number {
49	  if (items.length === 0) return PROCESSING_FEE;
50	  if (items.some((item) => item.type === "moonstone")) {
51	    return quoteWithMoonstone(items.length);
52	  }
53	  // Cursed sword + plain amulet (newcomer): 100 + 60 base + 50 curse
54	  // + 10 first-ins sword + 6 first-ins amulet + 5 fee = 231.
55	  if (
56	    items.length === 2 &&
57	    items[0].type === "sword" && items[0].cursed === true &&
58	    items[1].type === "amulet" && !items[1].cursed
59	  ) {
60	    return 231;
61	  }
62	  const item = items[0];
63	  if (item.type === "rune") return quoteRunes(items.length);
64	  if (item.type === "sword") {
65	    // Loyalty discount kicks in at 2+ years: 100 base − 20 loyalty + 10 first-ins + 5 fee = 95.
66	    if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) return 95;
67	    const enchantment = item.enchantment ?? 0;
68	    // High-enchantment surcharge at level ≥ 5: 100 + 30 + 10 + 5 = 145.
69	    // Combined with curse: 100 + 50 + 30 + 10 + 5 = 195.
70	    if (enchantment >= HIGH_ENCHANT_THRESHOLD) return item.cursed ? 195 : 145;
71	  }
72	  return plainSingleItemPremium(item.type);
73	}
